// App.js
import React, { useEffect, useState } from "react";
import { Routes, Route, Navigate } from "react-router-dom";

import Login from "./Login";
import Home from "./Home";
import Profile from "./Profile";
import Dashboard from "./Dashboard";
import AddNew from "./AddNew";
import Tools from "./Tools";
import ToolsGraph from "./ToolsGraph";
import UploadBills from "./UploadBills";
import History from "./History.jsx";
import TravelHistory from "./TravelHistory";
import TicketHistory from "./TicketHistory";
import BillsHistory from "./BillsHistory";
import AddTravel from "./AddTravel";
import AddTicket from "./AddTicket";
import Settings from "./Settings";

export default function App() {
  // load employee from localStorage if present
  const [employee, setEmployee] = useState(() => {
    try {
      const raw = localStorage.getItem("prasa_employee");
      return raw ? JSON.parse(raw) : null;
    } catch {
      return null;
    }
  });

  useEffect(() => {
    // keep localStorage & state in sync
    if (employee) localStorage.setItem("prasa_employee", JSON.stringify(employee));
    else localStorage.removeItem("prasa_employee");
  }, [employee]);

  const handleLoginSuccess = (emp) => {
    setEmployee(emp);
    localStorage.setItem("prasa_employee", JSON.stringify(emp));
  };

  const handleLogout = () => {
    setEmployee(null);
    localStorage.removeItem("prasa_employee");
  };

  const requireAuth = (element) => (employee ? element : <Navigate to="/" replace />);

  return (
    <Routes>
      <Route path="/" element={<Login onLoginSuccess={handleLoginSuccess} />} />

      <Route path="/home" element={requireAuth(<Home employee={employee} />)} />
      <Route path="/profile" element={requireAuth(<Profile employee={employee} />)} />
      <Route path="/dashboard" element={requireAuth(<Dashboard employee={employee} onLogout={handleLogout} />)} />
      <Route path="/addnew" element={requireAuth(<AddNew employee={employee} />)} />
      <Route path="/add/travel" element={requireAuth(<AddTravel employee={employee} />)} />
      <Route path="/add/ticket" element={requireAuth(<AddTicket employee={employee} />)} />
      <Route path="/add/upload-bills" element={requireAuth(<UploadBills employee={employee} />)} />
      <Route path="/history" element={requireAuth(<History employee={employee} />)} />
      <Route path="/travel-history" element={requireAuth(<TravelHistory employee={employee} />)} />
      <Route path="/ticket-history" element={requireAuth(<TicketHistory employee={employee} />)} />
      <Route path="/bills-history" element={requireAuth(<BillsHistory employee={employee} />)} />
      <Route path="/tools" element={requireAuth(<Tools employee={employee} />)} />
      <Route path="/tools/graph" element={requireAuth(<ToolsGraph employee={employee} />)} />
      <Route path="/settings" element={requireAuth(<Settings employee={employee} />)} />
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}
